@namespace sv_0761cd684b2a4c2fab3b497c879bda9f.Components.Chat

<div class="channel-item @(IsActive ? "active" : "")" @onclick="OnClick">
    <div class="channel-name-row">
        <span class="channel-name"># @Channel.Name</span>
        @if (Channel.UnreadCount > 0)
        {
            <span class="unread-badge">@Channel.UnreadCount</span>
        }
    </div>
    <div class="channel-desc">@TruncatedDescription</div>
</div>

@code {
    [Parameter, EditorRequired] public Channel Channel { get; set; } = default!;
    [Parameter] public bool IsActive { get; set; }
    [Parameter] public EventCallback<int> OnSelected { get; set; }

    private string TruncatedDescription =>
        Channel.Description.Length > 40
            ? Channel.Description[..40] + "…"
            : Channel.Description;

    private Task OnClick() => OnSelected.InvokeAsync(Channel.Id);
}

@namespace sv_0761cd684b2a4c2fab3b497c879bda9f.Components.Chat

<div class="channel-sidebar">
    <div class="sidebar-header">
        <h5>Channels</h5>
    </div>
    <div class="channel-list">
        @foreach (var channel in Channels)
        {
            <ChannelItem Channel="channel"
                         IsActive="channel.Id == ActiveChannelId"
                         OnSelected="OnChannelSelected" />
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<Channel> Channels { get; set; } = [];
    [Parameter] public int ActiveChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }
}

@namespace sv_0761cd684b2a4c2fab3b497c879bda9f.Components.Chat

<div class="message-input-area">
    <textarea @bind="Text"
              @bind:event="oninput"
              @onkeydown="HandleKeyDown"
              placeholder="@Placeholder"
              rows="2"></textarea>
    <button class="btn-send" @onclick="Send" disabled="@string.IsNullOrWhiteSpace(Text)">
        @ButtonLabel
    </button>
</div>

@code {
    [Parameter] public string Placeholder { get; set; } = "Type a message…";
    [Parameter] public string ButtonLabel { get; set; } = "Send";
    [Parameter] public EventCallback<string> OnSend { get; set; }

    private string Text { get; set; } = "";

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await Send();
        }
    }

    private async Task Send()
    {
        if (string.IsNullOrWhiteSpace(Text)) return;
        var message = Text.Trim();
        Text = "";
        await OnSend.InvokeAsync(message);
    }
}

@namespace sv_0761cd684b2a4c2fab3b497c879bda9f.Components.Chat

<div class="message-bubble" @onmouseenter="() => _showActions = true" @onmouseleave="() => _showActions = false">
    <div class="message-header">
        <span class="message-author">@Message.Author</span>
        <span class="message-time">@FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="reaction-row">
            @foreach (var reaction in Message.Reactions)
            {
                <button class="reaction-badge" @onclick="() => OnReact.InvokeAsync((Message.Id, reaction.Emoji))">
                    @reaction.Emoji @reaction.Users.Count
                </button>
            }
        </div>
    }

    @if (ReplyCount > 0)
    {
        <button class="thread-link" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)">
            @ReplyCount @(ReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (_showActions)
    {
        <div class="message-actions">
            <button class="action-btn" title="Reply" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)">💬</button>
            <button class="action-btn" title="React" @onclick="ToggleEmojiPicker">😀</button>
        </div>

        @if (_showEmojiPicker)
        {
            <div class="emoji-picker">
                @foreach (var emoji in _emojis)
                {
                    <button class="emoji-btn" @onclick="() => PickEmoji(emoji)">@emoji</button>
                }
            </div>
        }
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public int ReplyCount { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private bool _showActions;
    private bool _showEmojiPicker;
    private static readonly string[] _emojis = ["👍", "❤️", "😂", "🎉", "🤔", "👀"];

    private void ToggleEmojiPicker() => _showEmojiPicker = !_showEmojiPicker;

    private async Task PickEmoji(string emoji)
    {
        _showEmojiPicker = false;
        await OnReact.InvokeAsync((Message.Id, emoji));
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

@namespace sv_0761cd684b2a4c2fab3b497c879bda9f.Components.Chat
@inject IJSRuntime JS
@implements IAsyncDisposable

<div class="message-area">
    <div class="message-area-header">
        <h4># @ChannelName</h4>
        <p>@ChannelDescription</p>
    </div>

    <div class="message-list" @ref="_messageListRef">
        @if (_loadingMore)
        {
            <div class="loading-indicator">Loading older messages…</div>
        }
        @if (!HasMoreMessages && Messages.Count > 0)
        {
            <div class="no-more-messages">Beginning of channel history</div>
        }
        @foreach (var msg in Messages)
        {
            <MessageBubble Message="msg"
                           ReplyCount="GetReplyCount(msg.Id)"
                           OnOpenThread="OnOpenThread"
                           OnReact="OnReact" />
        }
    </div>

    <MessageInput Placeholder="@($"Message #{ChannelName}")"
                  ButtonLabel="Send"
                  OnSend="OnSendMessage" />
</div>

@code {
    [Parameter, EditorRequired] public string ChannelName { get; set; } = "";
    [Parameter] public string ChannelDescription { get; set; } = "";
    [Parameter, EditorRequired] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, int> ThreadReplyCounts { get; set; } = [];
    [Parameter] public bool HasMoreMessages { get; set; } = true;
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }

    private ElementReference _messageListRef;
    private IJSObjectReference? _scrollModule;
    private DotNetObjectReference<MessageArea>? _dotNetRef;
    private bool _loadingMore;

    private int GetReplyCount(int messageId) =>
        ThreadReplyCounts.TryGetValue(messageId, out var count) ? count : 0;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _dotNetRef = DotNetObjectReference.Create(this);
            _scrollModule = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./_content/sv-0761cd684b2a4c2fab3b497c879bda9f/Components/Chat/MessageArea.razor.js");
            await _scrollModule.InvokeVoidAsync("init", _messageListRef, _dotNetRef);
        }
    }

    [JSInvokable]
    public async Task OnScrolledToTop()
    {
        if (_loadingMore || !HasMoreMessages) return;
        _loadingMore = true;
        StateHasChanged();
        await OnLoadMore.InvokeAsync();
        _loadingMore = false;
        StateHasChanged();
    }

    public async ValueTask DisposeAsync()
    {
        if (_scrollModule is not null)
        {
            try { await _scrollModule.InvokeVoidAsync("dispose"); } catch (JSDisconnectedException) { }
            await _scrollModule.DisposeAsync();
        }
        _dotNetRef?.Dispose();
    }
}

let scrollElement = null;
let dotNetRef = null;
let handler = null;

export function init(element, ref) {
    scrollElement = element;
    dotNetRef = ref;
    handler = () => {
        if (scrollElement.scrollTop === 0) {
            dotNetRef.invokeMethodAsync('OnScrolledToTop');
        }
    };
    scrollElement.addEventListener('scroll', handler);
    // Scroll to bottom on init
    scrollElement.scrollTop = scrollElement.scrollHeight;
}

export function dispose() {
    if (scrollElement && handler) {
        scrollElement.removeEventListener('scroll', handler);
    }
    scrollElement = null;
    dotNetRef = null;
    handler = null;
}

@namespace sv_0761cd684b2a4c2fab3b497c879bda9f.Components.Chat

<div class="thread-panel">
    <div class="thread-header">
        <h5>Thread</h5>
        <button class="btn-close-thread" @onclick="OnClose">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root-message">
            <span class="message-author">@RootMessage.Author</span>
            <p class="message-content">@RootMessage.Content</p>
        </div>

        <div class="thread-divider">
            <span>@Replies.Count @(Replies.Count == 1 ? "reply" : "replies")</span>
        </div>

        <div class="thread-messages">
            @foreach (var reply in Replies)
            {
                <div class="thread-reply">
                    <div class="message-header">
                        <span class="message-author">@reply.Author</span>
                        <span class="message-time">@FormatRelativeTime(reply.SentAt)</span>
                    </div>
                    <div class="message-content">@reply.Content</div>
                </div>
            }
        </div>

        <MessageInput Placeholder="Reply in thread…"
                      ButtonLabel="Reply"
                      OnSend="OnSendReply" />
    }
</div>

@code {
    [Parameter] public Message? RootMessage { get; set; }
    [Parameter] public List<Message> Replies { get; set; } = [];
    [Parameter] public EventCallback<string> OnSendReply { get; set; }
    [Parameter] public EventCallback OnClose { get; set; }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

