.channel-item {
    padding: 8px 16px;
    cursor: pointer;
    transition: background 0.15s;
}

.channel-item:hover {
    background: #2c2f33;
}

.channel-item.active {
    background: #1264a3;
    color: #fff;
}

.channel-name-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
}

.channel-name {
    font-weight: 600;
    font-size: 0.95rem;
}

.unread-badge {
    background: #e01e5a;
    color: #fff;
    font-size: 0.75rem;
    font-weight: 700;
    padding: 1px 7px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
}

.channel-desc {
    font-size: 0.8rem;
    color: #999;
    margin-top: 2px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.channel-item.active .channel-desc {
    color: rgba(255, 255, 255, 0.7);
}

