.message-input-area {
    display: flex;
    gap: 8px;
    padding: 12px 20px;
    border-top: 1px solid #e0e0e0;
    background: #fff;
}

.message-input-area textarea {
    flex: 1;
    resize: none;
    border: 1px solid #ccc;
    border-radius: 6px;
    padding: 8px 12px;
    font-size: 0.95rem;
    font-family: inherit;
    outline: none;
    transition: border-color 0.15s;
}

.message-input-area textarea:focus {
    border-color: #1264a3;
}

.btn-send {
    padding: 8px 20px;
    background: #1264a3;
    color: #fff;
    border: none;
    border-radius: 6px;
    font-weight: 600;
    cursor: pointer;
    transition: background 0.15s;
    white-space: nowrap;
}

.btn-send:hover:not(:disabled) {
    background: #0d4f82;
}

.btn-send:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

