.thread-panel {
    width: 340px;
    min-width: 340px;
    flex: 25;
    display: flex;
    flex-direction: column;
    border-left: 1px solid #e0e0e0;
    background: #fafafa;
}

.thread-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 12px 16px;
    border-bottom: 1px solid #e0e0e0;
    background: #fff;
}

.thread-header h5 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
}

.btn-close-thread {
    padding: 4px 8px;
    border: none;
    background: transparent;
    font-size: 1.1rem;
    cursor: pointer;
    border-radius: 4px;
    color: #666;
    transition: background 0.1s;
}

.btn-close-thread:hover {
    background: #eee;
    color: #333;
}

.thread-root-message {
    padding: 12px 16px;
    border-bottom: 1px solid #e0e0e0;
    background: #fff;
}

.thread-root-message .message-author {
    font-weight: 700;
    font-size: 0.9rem;
}

.thread-root-message .message-content {
    margin: 4px 0 0;
    font-size: 0.9rem;
    color: #333;
}

.thread-divider {
    padding: 8px 16px;
    font-size: 0.8rem;
    color: #888;
    border-bottom: 1px solid #e0e0e0;
}

.thread-messages {
    flex: 1;
    overflow-y: auto;
    padding: 8px 16px;
    display: flex;
    flex-direction: column;
    gap: 8px;
}

.thread-reply {
    padding: 6px 0;
}

.thread-reply .message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
}

.thread-reply .message-author {
    font-weight: 700;
    font-size: 0.85rem;
}

.thread-reply .message-time {
    font-size: 0.7rem;
    color: #999;
}

.thread-reply .message-content {
    margin: 2px 0 0;
    font-size: 0.9rem;
    color: #333;
}

